#!/usr/bin/env python3
"""
scripts/render_report.py — Nebula branded PDF report generator v2
Run: python scripts/render_report.py --report out/report.json --out out/nebula_report.pdf
"""
from __future__ import annotations
import argparse, base64, io, json
from reportlab.lib.pagesizes import A4
from reportlab.lib import colors
from reportlab.lib.units import mm
from reportlab.lib.styles import ParagraphStyle
from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT
from reportlab.platypus import (
    SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
    HRFlowable, PageBreak, KeepTogether, Image,
)
from reportlab.platypus import Flowable

LOGO_B64 = """"""

# ── Brand colours ─────────────────────────────────────────────────────────────
NAVY        = colors.HexColor("#071333")
CREAM       = colors.HexColor("#FBF7E7")
TEAL        = colors.HexColor("#1B8C8C")
TEAL_LIGHT  = colors.HexColor("#E6F4F4")
AMBER       = colors.HexColor("#E8A020")
AMBER_LIGHT = colors.HexColor("#FEF6E8")
RED         = colors.HexColor("#C0392B")
RED_LIGHT   = colors.HexColor("#FDEDEC")
GREEN       = colors.HexColor("#1E8449")
GREEN_LIGHT = colors.HexColor("#E9F7EF")
GREY_DARK   = colors.HexColor("#4A4A4A")
GREY_MID    = colors.HexColor("#7F8C8D")
GREY_LIGHT  = colors.HexColor("#F2F4F5")
WHITE       = colors.white

PAGE_W, PAGE_H = A4
MARGIN  = 18 * mm
BRAND   = "NEBULA"
TAGLINE = "TRANSFORMING LIVES THROUGH WELLNESS"

def _hex(c):
    return f"{int(round(c.red*255)):02X}{int(round(c.green*255)):02X}{int(round(c.blue*255)):02X}"
def _grade_hex(g): return {"Strong":_hex(GREEN),"Moderate":_hex(AMBER)}.get(g, _hex(GREY_MID))
def _score_hex(s): return _hex(GREEN) if s>=80 else (_hex(AMBER) if s>=60 else _hex(GREY_MID))

def _logo_img(w_mm, h_mm):
    try:
        buf = io.BytesIO(base64.b64decode(LOGO_B64))
        return Image(buf, width=w_mm*mm, height=h_mm*mm)
    except Exception:
        return None

# ── Styles ────────────────────────────────────────────────────────────────────
def ps(name, **kw): return ParagraphStyle(name, **kw)

S = {
    "cover_title":    ps("ct",  fontName="Helvetica-Bold", fontSize=26, textColor=CREAM,   leading=32, alignment=TA_CENTER),
    "cover_sub":      ps("cs",  fontName="Helvetica",      fontSize=11, textColor=colors.HexColor("#C8D8E8"), leading=16, alignment=TA_CENTER),
    "cover_meta":     ps("cm",  fontName="Helvetica",      fontSize=8,  textColor=colors.HexColor("#8BACC8"), leading=12, alignment=TA_CENTER),
    "section_header": ps("sh",  fontName="Helvetica-Bold", fontSize=14, textColor=NAVY,    leading=18, spaceBefore=6, spaceAfter=3),
    "card_title":     ps("cdt", fontName="Helvetica-Bold", fontSize=11, textColor=NAVY,    leading=14),
    "body":           ps("b",   fontName="Helvetica",      fontSize=9.5,textColor=GREY_DARK,leading=14, spaceAfter=4),
    "body_small":     ps("bs",  fontName="Helvetica",      fontSize=8.5,textColor=GREY_MID, leading=12, spaceAfter=2),
    "action_text":    ps("at",  fontName="Helvetica",      fontSize=9,  textColor=colors.HexColor("#1A5276"), leading=13),
    "disclaimer":     ps("dt",  fontName="Helvetica-Oblique", fontSize=8, textColor=GREY_MID, leading=11, spaceAfter=2),
    "watchlist_body": ps("wb",  fontName="Helvetica",      fontSize=9.5,textColor=GREY_DARK,leading=14),
    "next_step":      ps("ns",  fontName="Helvetica",      fontSize=9.5,textColor=GREY_DARK,leading=13, leftIndent=10),
    "sum_num":        ps("sn",  fontName="Helvetica-Bold", fontSize=26, textColor=TEAL,    leading=30, alignment=TA_CENTER),
    "sum_lbl":        ps("sl",  fontName="Helvetica",      fontSize=8,  textColor=GREY_MID, leading=11, alignment=TA_CENTER),
    "prs_cond":       ps("prc", fontName="Helvetica-Bold", fontSize=11, textColor=NAVY,    leading=14, alignment=TA_CENTER),
    "prs_band":       ps("prb", fontName="Helvetica-Bold", fontSize=8,  textColor=WHITE,   leading=10, alignment=TA_CENTER),
    "prs_pct":        ps("prp", fontName="Helvetica",      fontSize=8,  textColor=GREY_MID, leading=10, alignment=TA_CENTER),
    "prs_desc":       ps("prd", fontName="Helvetica",      fontSize=7.5,textColor=GREY_MID, leading=10, alignment=TA_CENTER),
}

# ── Flowables ─────────────────────────────────────────────────────────────────
class ColorBar(Flowable):
    def __init__(self, color, height=3):
        super().__init__(); self.color=color; self.height=height; self.width=PAGE_W-2*MARGIN
    def draw(self):
        self.canv.setFillColor(self.color)
        self.canv.rect(0, 0, self.width, self.height, fill=1, stroke=0)

class PopulationBar(Flowable):
    """Shows a gradient risk band bar with a marker at the given percentile."""
    def __init__(self, pct, width=None, height=12):
        super().__init__()
        self.pct       = max(1, min(99, pct))
        self.bar_width = width or (PAGE_W - 2*MARGIN - 20*mm)
        self.height    = height
    def draw(self):
        w = self.bar_width; h = self.height; c = self.canv
        # Segmented bar: LOW(green) | AVERAGE(teal) | ELEVATED(amber) | HIGH(red)
        segments = [
            (0.25, GREEN),
            (0.50, TEAL),
            (0.75, AMBER),
            (1.00, RED),
        ]
        prev = 0
        for end_frac, col in segments:
            seg_w = w * (end_frac - prev)
            c.setFillColor(col)
            c.rect(prev*w, 0, seg_w, h, fill=1, stroke=0)
            prev = end_frac
        # Marker line
        mx = w * (self.pct / 100)
        c.setFillColor(WHITE)
        c.setStrokeColor(WHITE)
        c.setLineWidth(2)
        c.line(mx, -2, mx, h+2)
        # Triangle marker (upward pointing)
        c.setFillColor(WHITE)
        p = c.beginPath()
        p.moveTo(mx, h+8)
        p.lineTo(mx-4, h+1)
        p.lineTo(mx+4, h+1)
        p.close()
        c.drawPath(p, fill=1, stroke=0)

def hr(col=None, t=1): return HRFlowable(width="100%", thickness=t, color=col or GREY_LIGHT, spaceAfter=4, spaceBefore=4)
def sp(h=4): return Spacer(1, h)

def conf_bar(score):
    f  = max(0, min(10, int(score/10)))
    b  = "I"*f + "."*(10-f)
    hx = _score_hex(score)
    return Paragraph(f'<font color="#{hx}"><b>{b}</b></font>  <b>{score}%</b>',
        ps("cb", fontName="Helvetica", fontSize=8, textColor=GREY_DARK, leading=10))

def tier_cols(tier):
    return {"tier_1":(TEAL,TEAL_LIGHT,"TIER 1 - WELLNESS"),
            "tier_2":(AMBER,AMBER_LIGHT,"TIER 2 - PHYSICIAN REVIEW"),
            "tier_3":(RED,RED_LIGHT,"TIER 3 - URGENT")}.get(tier,(GREY_MID,GREY_LIGHT,tier.upper()))

def grade_col(g): return {"Strong":GREEN,"Moderate":AMBER}.get(g, GREY_MID)

def _risk_band(pct):
    if pct < 25:  return "LOW RISK",      GREEN
    if pct < 50:  return "BELOW AVERAGE", TEAL
    if pct < 75:  return "ABOVE AVERAGE", AMBER
    return              "ELEVATED RISK",  RED

# ── Footer ────────────────────────────────────────────────────────────────────
def on_page(canvas, doc):
    canvas.saveState()
    canvas.setFillColor(NAVY)
    canvas.rect(0, 0, PAGE_W, 10*mm, fill=1, stroke=0)
    canvas.setFillColor(colors.HexColor("#A0B4C4"))
    canvas.setFont("Helvetica", 7)
    canvas.drawString(MARGIN, 3.5*mm, f"{BRAND}  |  {TAGLINE}  |  CONFIDENTIAL - NOT FOR CLINICAL USE")
    canvas.drawRightString(PAGE_W-MARGIN, 3.5*mm, f"Page {doc.page}")
    canvas.restoreState()

# ── Cover ─────────────────────────────────────────────────────────────────────
def build_cover(report):
    story   = []
    summary = report.get("summary", {})
    cw      = PAGE_W - 2*MARGIN

    # Full-width navy cover block with centered logo
    logo = _logo_img(70, 52)  # wider + taller at full res

    title_para = Paragraph("Your Genetic Wellness Report", S["cover_title"])
    sub_para   = Paragraph(
        "Personalised insights from your DNA - fitness, nutrition, recovery and health risk findings.",
        S["cover_sub"])
    meta_text  = (f"Sample ID: {report.get('sample_id','Unknown')}  "
                  f"|  Generated: {report.get('generated_at','')[:10]}  "
                  f"|  Pipeline v{report.get('pipeline_version','0.1')}")
    meta_para  = Paragraph(meta_text, S["cover_meta"])

    logo_elem = logo if logo else Paragraph(
        f'<font color="#1B8C8C"><b>NEBULA</b></font>',
        ps("wm", fontName="Helvetica-Bold", fontSize=18, textColor=TEAL, leading=22, alignment=TA_CENTER))

    hdr_rows = [
        [sp(10)],
        [logo_elem],
        [sp(16)],
        [title_para],
        [sp(6)],
        [sub_para],
        [sp(20)],
        [meta_para],
        [sp(14)],
    ]
    hdr = Table(hdr_rows, colWidths=[cw])
    hdr.setStyle(TableStyle([
        ("BACKGROUND",    (0,0),(-1,-1), NAVY),
        ("LEFTPADDING",   (0,0),(-1,-1), 10),
        ("RIGHTPADDING",  (0,0),(-1,-1), 10),
        ("TOPPADDING",    (0,0),(-1,-1), 0),
        ("BOTTOMPADDING", (0,0),(-1,-1), 0),
        ("ALIGN",         (0,0),(-1,-1), "CENTER"),
    ]))
    story.append(hdr)
    story.append(sp(12))

    # Stat boxes
    stats = [
        (str(summary.get("total_insights",0)),          "Total Insights"),
        (str(summary.get("strong_evidence_count",0)),   "Strong Evidence"),
        (str(summary.get("moderate_evidence_count",0)), "Moderate Evidence"),
        (str(len(summary.get("referral_triggers",[]))), "Physician Flags"),
    ]
    bw = cw/4 - 2*mm
    cells = []
    for v,l in stats:
        c = Table([[Paragraph(v,S["sum_num"])],[Paragraph(l,S["sum_lbl"])]],colWidths=[bw])
        c.setStyle(TableStyle([
            ("BACKGROUND",(0,0),(-1,-1),GREY_LIGHT),
            ("TOPPADDING",(0,0),(-1,-1),10),("BOTTOMPADDING",(0,0),(-1,-1),10),
            ("LEFTPADDING",(0,0),(-1,-1),4),("RIGHTPADDING",(0,0),(-1,-1),4),
        ]))
        cells.append(c)
    st = Table([cells], colWidths=[bw]*4, hAlign="LEFT")
    st.setStyle(TableStyle([("LEFTPADDING",(0,0),(-1,-1),2),("RIGHTPADDING",(0,0),(-1,-1),2)]))
    story.append(st)
    story.append(sp(14))

    # Top highlights
    top = summary.get("top_insights",[])
    if top:
        story.append(Paragraph("Report Highlights", S["section_header"]))
        story.append(hr(TEAL, 2)); story.append(sp(6))
        for i,ins in enumerate(top[:3], 1):
            row = Table([[
                Paragraph(f"<b>{i}</b>", ps("num", fontName="Helvetica-Bold",
                    fontSize=14, textColor=TEAL, leading=16, alignment=TA_CENTER)),
                Paragraph(str(ins).rstrip("."), S["body"]),
            ]], colWidths=[10*mm, cw-14*mm])
            row.setStyle(TableStyle([("VALIGN",(0,0),(-1,-1),"TOP"),
                ("LEFTPADDING",(0,0),(-1,-1),4),("TOPPADDING",(0,0),(-1,-1),4),
                ("BOTTOMPADDING",(0,0),(-1,-1),4)]))
            story.append(row); story.append(sp(3))

    # ── PRS section — redesigned ─────────────────────────────────────────────
    prs_list = report.get("prs_scores",[])
    if prs_list:
        story.append(sp(10))
        story.append(Paragraph("Polygenic Risk Scores", S["section_header"]))
        story.append(hr(TEAL, 2)); story.append(sp(8))

        # Legend
        legend_items = [("LOW", GREEN), ("BELOW AVG", TEAL), ("ABOVE AVG", AMBER), ("ELEVATED", RED)]
        leg_cells = []
        for lbl,col in legend_items:
            lc = Table([[Paragraph(f"<b>{lbl}</b>",
                ps("ll", fontName="Helvetica-Bold", fontSize=7, textColor=WHITE, leading=9, alignment=TA_CENTER))]],
                colWidths=[22*mm])
            lc.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),col),
                ("TOPPADDING",(0,0),(-1,-1),3),("BOTTOMPADDING",(0,0),(-1,-1),3)]))
            leg_cells.append(lc)
        leg_t = Table([leg_cells], colWidths=[22*mm]*4, hAlign="LEFT")
        leg_t.setStyle(TableStyle([("LEFTPADDING",(0,0),(-1,-1),2),("RIGHTPADDING",(0,0),(-1,-1),2)]))
        story.append(leg_t); story.append(sp(10))

        for prs in prs_list:
            pct       = prs.get("percentile", 50)
            band_lbl, band_col = _risk_band(pct)
            bar_w     = cw - 60*mm

            band_badge = Table([[Paragraph(f"<b>{band_lbl}</b>", S["prs_band"])]],
                colWidths=[28*mm])
            band_badge.setStyle(TableStyle([
                ("BACKGROUND",(0,0),(-1,-1),band_col),
                ("TOPPADDING",(0,0),(-1,-1),4),("BOTTOMPADDING",(0,0),(-1,-1),4),
                ("LEFTPADDING",(0,0),(-1,-1),4),("RIGHTPADDING",(0,0),(-1,-1),4),
            ]))

            bar_col_content = [
                [Paragraph(f"Population percentile: <b>{pct:.0f}th</b>", S["prs_pct"])],
                [sp(3)],
                [PopulationBar(pct, width=bar_w, height=12)],
                [sp(2)],
                [Paragraph(f"0th        25th        50th        75th        100th", S["prs_desc"])],
                [sp(3)],
                [Paragraph(prs.get("interpretation",""), S["prs_desc"])],
            ]
            bar_table = Table(bar_col_content, colWidths=[bar_w])
            bar_table.setStyle(TableStyle([
                ("LEFTPADDING",(0,0),(-1,-1),0),("RIGHTPADDING",(0,0),(-1,-1),0),
                ("TOPPADDING",(0,0),(-1,-1),0),("BOTTOMPADDING",(0,0),(-1,-1),0),
            ]))

            row = Table([[
                Paragraph(f"<b>{prs.get('condition','')}</b>",
                    ps("prc2", fontName="Helvetica-Bold", fontSize=13, textColor=NAVY,
                       leading=16, alignment=TA_CENTER)),
                sp(1),
                band_badge,
                sp(1),
                bar_table,
            ]], colWidths=[18*mm, 3*mm, 30*mm, 4*mm, bar_w])
            row.setStyle(TableStyle([
                ("VALIGN",(0,0),(-1,-1),"MIDDLE"),
                ("LEFTPADDING",(0,0),(-1,-1),0),("RIGHTPADDING",(0,0),(-1,-1),0),
                ("TOPPADDING",(0,0),(-1,-1),0),("BOTTOMPADDING",(0,0),(-1,-1),0),
            ]))

            prs_card = Table([[row]], colWidths=[cw])
            prs_card.setStyle(TableStyle([
                ("BACKGROUND",(0,0),(-1,-1),GREY_LIGHT),
                ("TOPPADDING",(0,0),(-1,-1),10),("BOTTOMPADDING",(0,0),(-1,-1),10),
                ("LEFTPADDING",(0,0),(-1,-1),10),("RIGHTPADDING",(0,0),(-1,-1),10),
                ("BOX",(0,0),(-1,-1),0.5,colors.HexColor("#D0D8E0")),
            ]))
            story.append(prs_card); story.append(sp(6))

    story.append(PageBreak())
    return story

# ── Insight card ──────────────────────────────────────────────────────────────
def insight_card(rule):
    _,bg,_ = tier_cols(rule.get("output_tier","tier_1"))
    gc=grade_col(rule.get("evidence_grade","Exploratory")); gh=_hex(gc); cw=PAGE_W-2*MARGIN
    header=Table([[
        Paragraph(f"<b>{rule.get('rule_id','')}</b>  |  {rule.get('category','')}",S["card_title"]),
        Paragraph(f'<font color="#{gh}"><b>{rule.get("evidence_grade","").upper()}</b></font>',
            ps("gb",fontName="Helvetica-Bold",fontSize=8,textColor=gc,leading=10,alignment=TA_RIGHT)),
    ]],colWidths=[cw-30*mm,30*mm])
    header.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),bg),("TOPPADDING",(0,0),(-1,-1),7),
        ("BOTTOMPADDING",(0,0),(-1,-1),7),("LEFTPADDING",(0,0),(0,0),10),
        ("RIGHTPADDING",(-1,0),(-1,0),10),("VALIGN",(0,0),(-1,-1),"MIDDLE")]))
    conf=Table([[Paragraph("<b>Confidence:</b>",ps("cl",fontName="Helvetica-Bold",
            fontSize=8,textColor=GREY_MID,leading=10)),conf_bar(rule.get("confidence_score",60)),
    ]],colWidths=[24*mm,cw-24*mm])
    conf.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),bg),("TOPPADDING",(0,0),(-1,-1),2),
        ("BOTTOMPADDING",(0,0),(-1,-1),4),("LEFTPADDING",(0,0),(-1,-1),10),("VALIGN",(0,0),(-1,-1),"MIDDLE")]))
    body=Table([[Paragraph(str(rule.get("recommendation_text","")).strip(),S["body"])]],colWidths=[cw])
    body.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),WHITE),("TOPPADDING",(0,0),(-1,-1),8),
        ("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),10),("RIGHTPADDING",(0,0),(-1,-1),10)]))
    action=Table([[
        Paragraph("<b>What to do:</b>",ps("al",fontName="Helvetica-Bold",fontSize=8,textColor=TEAL,leading=10)),
        Paragraph(str(rule.get("practical_action","")).strip(),S["action_text"]),
    ]],colWidths=[22*mm,cw-24*mm])
    action.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),TEAL_LIGHT),("TOPPADDING",(0,0),(-1,-1),6),
        ("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),10),
        ("RIGHTPADDING",(0,0),(-1,-1),8),("VALIGN",(0,0),(-1,-1),"TOP")]))
    src="  |  ".join(rule.get("data_sources",[]))
    sources=Table([[Paragraph(f"<b>Sources:</b>  {src}",S["body_small"])]],colWidths=[cw])
    sources.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),GREY_LIGHT),("TOPPADDING",(0,0),(-1,-1),4),
        ("BOTTOMPADDING",(0,0),(-1,-1),4),("LEFTPADDING",(0,0),(-1,-1),10),("RIGHTPADDING",(0,0),(-1,-1),10)]))
    disc=Table([[Paragraph(str(rule.get("disclaimer","")).strip(),S["disclaimer"])]],colWidths=[cw])
    disc.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),WHITE),("TOPPADDING",(0,0),(-1,-1),4),
        ("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),10),
        ("RIGHTPADDING",(0,0),(-1,-1),10),("LINEABOVE",(0,0),(-1,0),0.5,colors.HexColor("#E0E0E0"))]))
    card=Table([[r] for r in [header,conf,body,action,sources,disc]],colWidths=[cw])
    card.setStyle(TableStyle([("BOX",(0,0),(-1,-1),1,colors.HexColor("#D0D8E0")),
        ("LEFTPADDING",(0,0),(-1,-1),0),("RIGHTPADDING",(0,0),(-1,-1),0),
        ("TOPPADDING",(0,0),(-1,-1),0),("BOTTOMPADDING",(0,0),(-1,-1),0)]))
    return KeepTogether([card,sp(8)])

# ── Watchlist card ────────────────────────────────────────────────────────────
def watchlist_card(rule):
    _,bg,tier_label=tier_cols(rule.get("output_tier","tier_2")); cw=PAGE_W-2*MARGIN
    if rule.get("output_tier")=="tier_3":
        h=Table([[Paragraph("TIER 3 - CLINICAL REFERRAL REQUIRED",
            ps("t3h",fontName="Helvetica-Bold",fontSize=11,textColor=WHITE,leading=14))]],colWidths=[cw])
        h.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),RED),("TOPPADDING",(0,0),(-1,-1),10),
            ("BOTTOMPADDING",(0,0),(-1,-1),10),("LEFTPADDING",(0,0),(-1,-1),12)]))
        b=Table([[Paragraph(f"<b>{rule.get('rule_id','')}</b> - This finding requires mandatory review by a genetic counsellor.",
            S["watchlist_body"])]],colWidths=[cw])
        b.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),RED_LIGHT),("TOPPADDING",(0,0),(-1,-1),10),
            ("BOTTOMPADDING",(0,0),(-1,-1),10),("LEFTPADDING",(0,0),(-1,-1),12),("RIGHTPADDING",(0,0),(-1,-1),12)]))
        a=Table([[Paragraph("<b>Action:</b>  "+str(rule.get("practical_action","")).strip(),S["action_text"])]],colWidths=[cw])
        a.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),AMBER_LIGHT),("TOPPADDING",(0,0),(-1,-1),8),
            ("BOTTOMPADDING",(0,0),(-1,-1),8),("LEFTPADDING",(0,0),(-1,-1),12),("RIGHTPADDING",(0,0),(-1,-1),12)]))
        card=Table([[h],[b],[a]],colWidths=[cw])
        card.setStyle(TableStyle([("BOX",(0,0),(-1,-1),1.5,RED),
            ("LEFTPADDING",(0,0),(-1,-1),0),("RIGHTPADDING",(0,0),(-1,-1),0),
            ("TOPPADDING",(0,0),(-1,-1),0),("BOTTOMPADDING",(0,0),(-1,-1),0)]))
        return KeepTogether([card,sp(8)])
    header=Table([[
        Paragraph(f"{tier_label}",ps("wh",fontName="Helvetica-Bold",fontSize=10,textColor=WHITE,leading=13)),
        Paragraph(f"<b>{rule.get('rule_id','')}</b>  |  {rule.get('category','')}",
            ps("wid",fontName="Helvetica-Bold",fontSize=10,textColor=WHITE,leading=13,alignment=TA_RIGHT)),
    ]],colWidths=[cw/2,cw/2])
    header.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),AMBER),("TOPPADDING",(0,0),(-1,-1),8),
        ("BOTTOMPADDING",(0,0),(-1,-1),8),("LEFTPADDING",(0,0),(-1,-1),10),
        ("RIGHTPADDING",(0,0),(-1,-1),10),("VALIGN",(0,0),(-1,-1),"MIDDLE")]))
    body=Table([[Paragraph(str(rule.get("recommendation_text","")).strip(),S["watchlist_body"])]],colWidths=[cw])
    body.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),AMBER_LIGHT),("TOPPADDING",(0,0),(-1,-1),8),
        ("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),10),("RIGHTPADDING",(0,0),(-1,-1),10)]))
    act=Table([[Paragraph("<b>Action required:</b>  "+str(rule.get("practical_action","")).strip(),S["action_text"])]],colWidths=[cw])
    act.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),WHITE),("TOPPADDING",(0,0),(-1,-1),6),
        ("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),10),
        ("RIGHTPADDING",(0,0),(-1,-1),10),("LINEABOVE",(0,0),(-1,0),0.5,AMBER)]))
    meta=Table([[Paragraph(
        f"<b>Review:</b>  {rule.get('review_interval','')}  |  "
        f"<b>Evidence:</b>  {rule.get('evidence_grade','')}  |  "
        f"<b>Confidence:</b>  {rule.get('confidence_score','')}%",S["body_small"])]],colWidths=[cw])
    meta.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),GREY_LIGHT),("TOPPADDING",(0,0),(-1,-1),4),
        ("BOTTOMPADDING",(0,0),(-1,-1),4),("LEFTPADDING",(0,0),(-1,-1),10)]))
    card=Table([[header],[body],[act],[meta]],colWidths=[cw])
    card.setStyle(TableStyle([("BOX",(0,0),(-1,-1),1.5,AMBER),
        ("LEFTPADDING",(0,0),(-1,-1),0),("RIGHTPADDING",(0,0),(-1,-1),0),
        ("TOPPADDING",(0,0),(-1,-1),0),("BOTTOMPADDING",(0,0),(-1,-1),0)]))
    return KeepTogether([card,sp(8)])

# ── Sections ──────────────────────────────────────────────────────────────────
CAT_LABELS = {
    "Fitness":        "Fitness",
    "Nutrition":      "Nutrition",
    "Recovery/Sleep": "Recovery and Sleep",
    "Health Risk":    "Health Risk",
}

def build_insights(report):
    story=[]
    for cat,rules in report.get("insights",{}).items():
        if not rules: continue
        story.append(Paragraph(CAT_LABELS.get(cat,cat), S["section_header"]))
        story.append(ColorBar(TEAL, 3)); story.append(sp(8))
        t1=[r for r in rules if r.get("output_tier")=="tier_1"]
        for r in t1: story.append(insight_card(r))
        if not t1:
            story.append(Paragraph("All findings in this category require physician review - see Watchlist.",S["body_small"]))
        story.append(sp(6))
    return story

def build_watchlist(report):
    story=[]; wl=report.get("watchlist",[])
    if not wl: return story
    story.append(Paragraph("Physician Review Required", S["section_header"]))
    story.append(ColorBar(AMBER,3)); story.append(sp(4))
    story.append(Paragraph(
        "The following findings carry a physician or genetic counsellor referral flag. "
        "They are presented separately and require professional review before acting.", S["body"]))
    story.append(sp(8))
    for r in wl: story.append(watchlist_card(r))
    return story

def build_next_steps(report):
    story=[]; steps=report.get("next_steps",[])
    if not steps: return story
    story.append(Paragraph("Your Next Steps", S["section_header"]))
    story.append(ColorBar(TEAL,3)); story.append(sp(8))
    ucm={"urgent":RED,"recommended":AMBER,"routine":GREEN}
    ulm={"urgent":"URGENT","recommended":"RECOMMENDED","routine":"ROUTINE"}
    cw=PAGE_W-2*MARGIN; rows=[]
    for i,step in enumerate(steps,1):
        uc=ucm.get(step.get("urgency","routine"),GREY_MID)
        ul=ulm.get(step.get("urgency","routine"),"ROUTINE")
        ub=Table([[Paragraph(f"<b>{ul}</b>",ps("ul",fontName="Helvetica-Bold",fontSize=7,
            textColor=WHITE,leading=9,alignment=TA_CENTER))]],colWidths=[26*mm])
        ub.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,-1),uc),
            ("TOPPADDING",(0,0),(-1,-1),4),("BOTTOMPADDING",(0,0),(-1,-1),4)]))
        rows.append([
            Paragraph(f"<b>{i}</b>",ps("sn2",fontName="Helvetica-Bold",
                fontSize=14,textColor=TEAL,leading=16,alignment=TA_CENTER)),
            ub,
            Paragraph(f"<b>{step.get('action','')}</b><br/>"
                f"<font size='8' color='#7F8C8D'>{step.get('reason','')}</font>",S["next_step"])])
    t=Table(rows,colWidths=[10*mm,28*mm,cw-40*mm])
    t.setStyle(TableStyle([("VALIGN",(0,0),(-1,-1),"MIDDLE"),("TOPPADDING",(0,0),(-1,-1),8),
        ("BOTTOMPADDING",(0,0),(-1,-1),8),("LEFTPADDING",(0,0),(-1,-1),4),
        ("ROWBACKGROUNDS",(0,0),(-1,-1),[WHITE,GREY_LIGHT]),
        ("LINEBELOW",(0,0),(-1,-2),0.5,colors.HexColor("#E0E0E0"))]))
    story.append(t); return story

def build_evidence_table(report):
    story=[]; evs=report.get("evidence_confidence",[])
    if not evs: return story
    story.append(PageBreak())
    story.append(Paragraph("Evidence and Confidence Table",S["section_header"]))
    story.append(ColorBar(TEAL,3)); story.append(sp(8))
    cw=PAGE_W-2*MARGIN
    rows=[[Paragraph("<b>Rule</b>",S["body_small"]),Paragraph("<b>Evidence Grade</b>",S["body_small"]),
        Paragraph("<b>Confidence</b>",S["body_small"]),Paragraph("<b>Data Sources</b>",S["body_small"])]]
    for ev in evs:
        grade=ev.get("evidence_grade",""); gh=_grade_hex(grade)
        rows.append([Paragraph(f"<b>{ev.get('recommendation_id','')}</b>",S["body_small"]),
            Paragraph(f'<font color="#{gh}"><b>{grade}</b></font>',S["body_small"]),
            conf_bar(ev.get("confidence_score",60)),
            Paragraph("<br/>".join(ev.get("data_sources",[])),S["body_small"])])
    t=Table(rows,colWidths=[18*mm,28*mm,38*mm,cw-86*mm])
    t.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),NAVY),("TEXTCOLOR",(0,0),(-1,0),WHITE),
        ("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,0),8),
        ("ROWBACKGROUNDS",(0,1),(-1,-1),[WHITE,GREY_LIGHT]),
        ("GRID",(0,0),(-1,-1),0.5,colors.HexColor("#D0D8E0")),
        ("VALIGN",(0,0),(-1,-1),"TOP"),("TOPPADDING",(0,0),(-1,-1),5),
        ("BOTTOMPADDING",(0,0),(-1,-1),5),("LEFTPADDING",(0,0),(-1,-1),5)]))
    story.append(t); return story

def build_disclaimers(report):
    story=[]; discs=report.get("disclaimers",[])
    if not discs: return story
    story.append(sp(16))
    story.append(Paragraph("Important Disclaimers",S["section_header"]))
    story.append(ColorBar(GREY_MID,2)); story.append(sp(8))
    for d in discs:
        story.append(Paragraph(f"  {d}",S["disclaimer"])); story.append(sp(3))
    return story

# ── Main ──────────────────────────────────────────────────────────────────────
def build_report(report_path, output_path):
    with open(report_path) as f: report=json.load(f)
    doc=SimpleDocTemplate(output_path,pagesize=A4,
        leftMargin=MARGIN,rightMargin=MARGIN,topMargin=MARGIN,bottomMargin=14*mm,
        title=f"Nebula - {report.get('sample_id','')}",author="Nebula")
    story=[]
    story+=build_cover(report)
    story+=build_insights(report)
    if report.get("watchlist"): story.append(PageBreak()); story+=build_watchlist(report)
    if report.get("next_steps"): story.append(PageBreak()); story+=build_next_steps(report)
    story+=build_evidence_table(report)
    story+=build_disclaimers(report)
    doc.build(story,onFirstPage=on_page,onLaterPages=on_page)
    print(f"Report written to {output_path}")

if __name__=="__main__":
    ap=argparse.ArgumentParser()
    ap.add_argument("--report",default="out/report.json")
    ap.add_argument("--out",default="out/nebula_report.pdf")
    args=ap.parse_args()
    build_report(args.report,args.out)
